code = """import pandas as pd
import json
import re

# Load clinical data (Breast patients)
clinical_file = locals()['var_function-call-12694098629810364530']
with open(clinical_file, 'r') as f:
    clinical_data = json.load(f)

# Load mutation data (CDH1)
mutation_file = locals()['var_function-call-4376391701503676073']
with open(mutation_file, 'r') as f:
    mutation_data = json.load(f)

# Create set of mutated barcodes
mutated_barcodes = set(item['ParticipantBarcode'] for item in mutation_data)

# Process clinical data
records = []
for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist_type = entry.get('histological_type', 'Unknown')
    
    # Check if Alive
    if 'Alive' not in desc:
        continue
        
    # Extract Barcode
    # Pattern: TCGA-XX-XXXX
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if match:
        barcode = match.group(1)
        
        is_mutated = 1 if barcode in mutated_barcodes else 0
        records.append({
            'histological_type': hist_type,
            'is_mutated': is_mutated
        })

# Create DataFrame
df = pd.DataFrame(records)

# Group by histological type
summary = df.groupby('histological_type').agg(
    total_count=('is_mutated', 'count'),
    mutation_count=('is_mutated', 'sum')
).reset_index()

# Calculate percentage
summary['percentage'] = (summary['mutation_count'] / summary['total_count']) * 100

# Sort by percentage descending
top_3 = summary.sort_values(by='percentage', ascending=False).head(3)

print("__RESULT__:")
print(top_3.to_json(orient='records'))"""

